Here's a modern MSTest test class using both `[DataRow]` and `[DynamicData]` with ValueTuples for your `PriceCalculator`:

```csharp
using Contoso.Pricing;

namespace Contoso.Pricing.Tests;

[TestClass]
public sealed class PriceCalculatorTests
{
    private readonly PriceCalculator _calculator;

    public PriceCalculatorTests()
    {
        _calculator = new PriceCalculator();
    }

    // ─── CalculateTotal: DataRow for simple inline cases ───

    [TestMethod]
    [DataRow(10.00, 1, 0.0, 10.00, DisplayName = "Single item, no tax")]
    [DataRow(10.00, 2, 0.0, 20.00, DisplayName = "Two items, no tax")]
    [DataRow(10.00, 1, 0.10, 11.00, DisplayName = "Single item, 10% tax")]
    [DataRow(25.50, 3, 0.08, 82.62, DisplayName = "Multiple items, 8% tax")]
    [DataRow(0.00, 5, 0.10, 0.00, DisplayName = "Zero price")]
    [DataRow(99.99, 0, 0.05, 0.00, DisplayName = "Zero quantity")]
    public void CalculateTotal_WithValidInputs_ReturnsExpected(
        double unitPrice, int quantity, double taxRate, double expected)
    {
        var result = _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate);

        Assert.AreEqual((decimal)expected, result);
    }

    [TestMethod]
    [DataRow(-1.00, 1, 0.10, DisplayName = "Negative price throws")]
    public void CalculateTotal_NegativePrice_Throws(double price, int qty, double tax)
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal((decimal)price, qty, (decimal)tax));
    }

    [TestMethod]
    [DataRow(10.00, -1, 0.10, DisplayName = "Negative quantity throws")]
    public void CalculateTotal_NegativeQuantity_Throws(double price, int qty, double tax)
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal((decimal)price, qty, (decimal)tax));
    }

    // ─── ApplyDiscount: DynamicData with ValueTuples (preferred for decimal precision) ───

    [TestMethod]
    [DynamicData(nameof(DiscountTestData))]
    public void ApplyDiscount_WithValidInputs_ReturnsExpected(
        decimal price, decimal discountPercent, decimal expected)
    {
        var result = _calculator.ApplyDiscount(price, discountPercent);

        Assert.AreEqual(expected, result);
    }

    public static IEnumerable<(decimal price, decimal discountPercent, decimal expected)> DiscountTestData =>
    [
        (100m, 0m, 100m),        // No discount
        (100m, 10m, 90m),        // 10% off
        (100m, 50m, 50m),        // Half price
        (100m, 100m, 0m),        // Full discount
        (200m, 25m, 150m),       // 25% off $200
        (49.99m, 15m, 42.4915m), // Fractional result
    ];

    [TestMethod]
    [DataRow(-1.0, DisplayName = "Negative discount throws")]
    [DataRow(101.0, DisplayName = "Over 100% discount throws")]
    public void ApplyDiscount_InvalidPercent_Throws(double discountPercent)
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.ApplyDiscount(100m, (decimal)discountPercent));
    }
}
```

**Key best practices applied:**

- **`sealed` class** — performance and design clarity
- **`[DataRow]`** — inline data for simple primitive inputs (note: `decimal` isn't allowed in attributes, so we use `double` and cast)
- **`[DynamicData]` with ValueTuples** — type-safe, supports `decimal` directly, preferred for complex/precise data (MSTest 3.7+)
- **`Assert.ThrowsExactly<T>`** — validates exceptions inline instead of `[ExpectedException]`
- **`DisplayName`** — descriptive names in test output
- **Constructor initialization** — enables `readonly` fields
- **Separate methods for valid/invalid inputs** — clear intent per test
